mapper.select:
SELECT REVIEW_ID, PRODUCT_ID, MEMBERNO, ORDER_ITEM_ID, RATING, REVIEW_CONTENT, REVIEW_IMG, REG_DATE
FROM market_review
WHERE REVIEW_ID = #{value}

mapper.update:
UPDATE market_review
SET 
    RATING = #{rating},
    REVIEW_CONTENT = #{review_content},
    REVIEW_IMG = #{review_img}
WHERE REVIEW_ID = #{review_id}

